import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { addSensor } from "../api/sensorsapi";
import { getActiveSensors, activateSensor } from "../api/activeapi";
import { getInactiveSensors, inactivateSensor } from "../api/inactiveapi";
import ConnectionModal from "../components/ConnectionModal";

const Sensor = () => {
  const navigate = useNavigate();
  const location = useLocation();

  
  const [sensors, setSensors] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [showConnectionModal, setShowConnectionModal] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");
  const [editSensor, setEditSensor] = useState(null);

  const [form, setForm] = useState({
    sensorName: "",
    location: "",
    topicName: "",
    quantity: "",
    unit: "",
  });

  const [errors, setErrors] = useState({});
  const [selectedSensor, setSelectedSensor] = useState(null);
  const [selectedFields, setSelectedFields] = useState([]);
  const [selectedInterval, setSelectedInterval] = useState("");

  const connectionId = Number(localStorage.getItem("sb_connectionId")) || 0;

  const fetchSensors = async () => {
    if (!connectionId) return;
    try {
      const data =
        activeTab === "active"
          ? await getActiveSensors(connectionId)
          : await getInactiveSensors(connectionId);

      if (Array.isArray(data)) {
        setSensors(
          data.map(s => ({
            ...s,
            status: s.isActive ? "active" : "inactive",
            id: s.sensorId,
          }))
        );
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (location.state?.showSuccess) {
      setSuccessMsg("Connected successfully!");
      setTimeout(() => setSuccessMsg(""), 3000);
    }
    fetchSensors();
  }, []);

  useEffect(() => {
    fetchSensors();
  }, [activeTab]);

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const filteredSensors = sensors;

  return (
    <div>
      {/* HEADER */}
      <div className="sb-page-header px-4 py-3 mb-4">
        <h5 className="sb-header-title mb-1">
          <i className="bi bi-broadcast me-2 sb-accent"></i>Sensors
        </h5>
        <p className="sb-header-subtitle mb-0">
          Manage and monitor your sensors.
        </p>
      </div>

      {/* SUCCESS MESSAGE */}
      {successMsg && (
        <div className="position-fixed top-0 end-0 m-4">
          <div className="alert alert-success shadow">{successMsg}</div>
        </div>
      )}

      {/* TOOLBAR */}
      <div className="container-fluid px-4">
        <div className="d-flex justify-content-between mb-4">
          <div className="d-flex gap-2">
            <button
              className={`btn ${
                activeTab === "active"
                  ? "sb-primary-btn"
                  : "btn-outline-secondary"
              }`}
              onClick={() => setActiveTab("active")}
            >
              Active
            </button>

            <button
              className={`btn ${
                activeTab === "inactive"
                  ? "sb-primary-btn"
                  : "btn-outline-secondary"
              }`}
              onClick={() => setActiveTab("inactive")}
            >
              Inactive
            </button>
          </div>

          <div className="d-flex gap-2">
            {/* ADD CONNECTION */}
            <button
              className="btn sb-connect-btn"
              onClick={() => setShowConnectionModal(true)}
            >
              <i className="bi bi-hdd-network me-1"></i>
              Add Connection
            </button>

            {/* ADD SENSOR */}
            <button
              className="btn sb-connect-btn"
              onClick={() => {
                setEditSensor(null);
                setForm({
                  sensorName: "",
                  location: "",
                  topicName: "",
                  quantity: "",
                  unit: "",
                });
                setErrors({});
                setShowForm(true);
              }}
            >
              <i className="bi bi-plus-circle-fill me-1"></i>
              Add Sensor
            </button>
          </div>
        </div>

        {/* SENSOR LIST */}
        {filteredSensors.length === 0 ? (
          <p className="text-muted">No sensors found.</p>
        ) : (
          <div className="row g-3">
            {filteredSensors.map(sensor => (
              <div className="col-md-4" key={sensor.id}>
                <div className="card p-3 shadow-sm">
                  <h6>{sensor.sensorName}</h6>
                  <small>{sensor.topicName}</small>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* CONNECTION MODAL */}
      {showConnectionModal && (
        <ConnectionModal
          onClose={() => setShowConnectionModal(false)}
          sensors={sensors}
        />
      )}
      {/* ADD SENSOR MODAL */}
{showForm && (
  <div className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
       style={{ backgroundColor: "rgba(0,0,0,0.6)", zIndex: 1050 }}>
    <div className="card p-4" style={{ width: "500px" }}>
      <h5>Add Sensor</h5>

      <input
        className="form-control mb-2"
        name="sensorName"
        placeholder="Sensor Name"
        value={form.sensorName}
        onChange={handleChange}
      />

      <input
        className="form-control mb-2"
        name="location"
        placeholder="Location"
        value={form.location}
        onChange={handleChange}
      />

      <input
        className="form-control mb-2"
        name="topicName"
        placeholder="Topic Name"
        value={form.topicName}
        onChange={handleChange}
      />

      <input
        className="form-control mb-2"
        name="quantity"
        placeholder="Quantity"
        value={form.quantity}
        onChange={handleChange}
      />

      <input
        className="form-control mb-3"
        name="unit"
        placeholder="Unit"
        value={form.unit}
        onChange={handleChange}
      />

      <div className="d-flex justify-content-end gap-2">
        <button className="btn btn-secondary" onClick={() => setShowForm(false)}>
          Cancel
        </button>
        <button className="btn sb-connect-btn" onClick={handleAddSensor}>
          Save
        </button>
      </div>
    </div>
  </div>
)}
``
    </div>
  );
};

export default Sensor;
